namespace bustub {

template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits) : cardinality_(0), n_leading_bits_(n_leading_bits) {
  if (n_leading_bits_ <= 0) {
    m_ = 0;
    dense_bucket_.clear();
    overflow_bucket_.clear();
  } else {
    m_ = 1U << n_leading_bits_;  // 2^n_leading_bits
    dense_bucket_.assign(m_, 0);
  }
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_leading_bits_ <= 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  hash_t hash = CalculateHash(val);

  // Extract bucket index from the first n_leading_bits
  uint32_t bucket_idx = hash & ((1U << n_leading_bits_) - 1);

  // Get remaining bits after removing the bucket index bits
  hash_t remaining = hash >> n_leading_bits_;

  // Calculate rho (position of leftmost 1 bit in remaining)
  uint64_t rho = 0;
  if (remaining == 0) {
    rho = 64 - n_leading_bits_ + 1;  // Maximum rho when no bits are set
  } else {
    // Count leading zeros and add 1
    rho = 64 - n_leading_bits_ - __builtin_clzll(remaining) + 1;
  }

  // Store rho in dense and overflow buckets
  uint8_t dense_val = static_cast<uint8_t>(rho & ((1U << DENSE_BUCKET_SIZE) - 1));
  uint8_t overflow_val = static_cast<uint8_t>((rho >> DENSE_BUCKET_SIZE) & ((1U << OVERFLOW_BUCKET_SIZE) - 1));

  // Update dense bucket with maximum value
  if (bucket_idx < dense_bucket_.size()) {
    uint8_t current_dense = dense_bucket_[bucket_idx].to_ulong();
    uint8_t current_overflow = 0;
    if (overflow_bucket_.find(bucket_idx) != overflow_bucket_.end()) {
      current_overflow = overflow_bucket_[bucket_idx].to_ulong();
    }

    // Reconstruct the full rho from dense and overflow
    uint64_t current_rho = current_dense | (static_cast<uint64_t>(current_overflow) << DENSE_BUCKET_SIZE);
    uint64_t new_rho = rho;

    if (new_rho > current_rho) {
      dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(dense_val);
      if (overflow_val > 0) {
        overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
      }
    }
  }
}

template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (n_leading_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Compute cardinality using standard HyperLogLog formula
  double raw_estimate = 0.0;
  uint32_t zeros = 0;

  for (uint32_t i = 0; i < m_; ++i) {
    uint8_t dense_val = dense_bucket_[i].to_ulong();
    uint8_t overflow_val = 0;

    if (overflow_bucket_.find(i) != overflow_bucket_.end()) {
      overflow_val = overflow_bucket_[i].to_ulong();
    }

    // Reconstruct the full rho value
    uint64_t rho = dense_val | (static_cast<uint64_t>(overflow_val) << DENSE_BUCKET_SIZE);

    if (rho == 0) {
      zeros++;
    }

    raw_estimate += std::pow(2.0, -static_cast<double>(rho));
  }

  double estimate = CONSTANT * static_cast<double>(m_) * static_cast<double>(m_) / raw_estimate;

  // Small range correction
  if (estimate <= 2.5 * m_) {
    if (zeros != 0) {
      estimate = m_ * std::log(static_cast<double>(m_) / static_cast<double>(zeros));
    }
  }
  // Large range correction
  else if (estimate <= (1.0 / 30.0) * (1ULL << 32)) {
    // No correction needed
  } else {
    estimate = -1.0 * (1ULL << 32) * std::log(1.0 - estimate / (1ULL << 32));
  }

  cardinality_ = static_cast<uint64_t>(estimate + 0.5);
}

