#include <algorithm>
#include <cmath>

namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  if (n_bits_ <= 0) {
    m_ = 0;
    registers_.clear();
  } else {
    m_ = 1U << n_bits_;  // 2^n_bits
    registers_.assign(m_, 0);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the leftmost 1 bit (rho function)
  // This is equivalent to finding the number of leading zeros + 1
  for (uint64_t i = BITSET_CAPACITY; i > 0; --i) {
    if (bset[i - 1]) {
      return BITSET_CAPACITY - i + 1;
    }
  }
  return BITSET_CAPACITY + 1;
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ <= 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  hash_t hash = CalculateHash(val);
  std::bitset<BITSET_CAPACITY> binary = ComputeBinary(hash);

  // Extract bucket index from the first n_bits
  uint32_t bucket_idx = hash & ((1U << n_bits_) - 1);

  // Get remaining bits after removing the bucket index bits
  hash_t remaining = hash >> n_bits_;
  std::bitset<BITSET_CAPACITY> remaining_bits(remaining);

  // Find position of leftmost one in remaining bits
  uint64_t rho = PositionOfLeftmostOne(remaining_bits);

  // Update the register with the maximum rho value
  if (bucket_idx < registers_.size()) {
    registers_[bucket_idx] = std::max(registers_[bucket_idx], static_cast<uint8_t>(rho));
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (n_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Standard HyperLogLog cardinality estimation formula
  // cardinality = CONSTANT * m^2 / sum(2^(-M[i]))
  double raw_estimate = 0.0;
  for (uint32_t i = 0; i < m_; ++i) {
    raw_estimate += std::pow(2.0, -static_cast<double>(registers_[i]));
  }

  double estimate = CONSTANT * static_cast<double>(m_) * static_cast<double>(m_) / raw_estimate;

  // Small range correction
  if (estimate <= 2.5 * m_) {
    uint32_t zeros = 0;
    for (uint32_t i = 0; i < m_; ++i) {
      if (registers_[i] == 0) {
        zeros++;
      }
    }
    if (zeros != 0) {
      estimate = m_ * std::log(static_cast<double>(m_) / static_cast<double>(zeros));
    }
  }
  // Large range correction
  else if (estimate <= (1.0 / 30.0) * (1ULL << 32)) {
    // No correction needed
  } else {
    estimate = -1.0 * (1ULL << 32) * std::log(1.0 - estimate / (1ULL << 32));
  }

  cardinality_ = static_cast<size_t>(estimate + 0.5);
}

